// Flatten webhook v2 body
return $input.all().map(item => ({
  json: item.json.body || item.json
}));

// Build dedup key and validate input
const d = $input.item.json;
const commentId = d.comment_id || d.id;
const postId = d.post_id;
const fromId = d.from_id;
const text = (d.text || '').trim();
const dedupKey = postId + '_' + commentId;

// Skip if from_id is negative (bot/group) or text is empty
const skipReason = fromId < 0 ? 'bot_comment' : (!text ? 'empty_text' : '');

return [{
  json: {
    comment_id: commentId,
    post_id: postId,
    from_id: fromId,
    owner_id: d.owner_id || -137949809,
    text: text,
    date: d.date || new Date().toISOString(),
    event_type: d.event_type || 'photo_comment_new',
    dedup_key: dedupKey,
    skip_reason: skipReason
  }
}];

// Check if dedup found existing record
const items = $input.all();
const hasData = items.length > 0 && items[0].json && Object.keys(items[0].json).length > 0 && items[0].json.ID_записи;
return [{ json: { is_duplicate: hasData } }];

// Collect context from VK API responses and original input
const input = $('Validate: Input').item.json;

// Get post context
let postText = '';
let postUrl = '';
try {
  const postResp = $('Context: Fetch Post').item.json;
  const items = postResp?.response?.items || postResp?.response || [];
  if (items.length > 0) {
    postText = (items[0].text || '').substring(0, 300);
    postUrl = `https://vk.com/wall${input.owner_id}_${input.post_id}`;
  }
} catch(e) { /* post fetch failed, continue without context */ }

// Get user name
let userName = '';
try {
  const userResp = $('Context: Fetch User').item.json;
  const users = userResp?.response || [];
  if (users.length > 0) {
    userName = (users[0].first_name || '') + ' ' + (users[0].last_name || '');
    userName = userName.trim();
  }
} catch(e) { /* user fetch failed, continue without name */ }

// Rule-based pre-parsing
const text = input.text;
const textUpper = text.toUpperCase().trim();

// Detect sizes
const sizePatterns = ['XXL', '3XL', '2XL', 'XL', 'XS', 'S', 'M', 'L'];
let detectedSize = '';
for (const s of sizePatterns) {
  if (new RegExp('\\b' + s + '\\b', 'i').test(textUpper)) {
    detectedSize = s;
    break;
  }
}

// Detect quantity
let detectedQty = 0;
const numMatch = text.match(/(\d+)\s*(шт|штук|штуки)?/i);
if (numMatch) {
  const n = parseInt(numMatch[1]);
  if (n >= 1 && n <= 99) detectedQty = n;
}

// Detect buy keywords
const buyKeywords = ['беру', 'куплю', 'купить', 'хочу', 'возьму', 'заказ', 'закажу', 'давай', 'мне'];
const hasBuyIntent = buyKeywords.some(kw => textUpper.includes(kw.toUpperCase()));

// Detect question markers
const questionMarkers = ['?', 'сколько', 'есть', 'когда', 'как', 'какой', 'какая', 'можно'];
const hasQuestion = questionMarkers.some(m => text.toLowerCase().includes(m));

return [{
  json: {
    ...input,
    post_text: postText,
    post_url: postUrl || `https://vk.com/wall${input.owner_id}_${input.post_id}`,
    user_name: userName || 'VK ID ' + input.from_id,
    pre_parse: {
      size: detectedSize,
      quantity: detectedQty,
      has_buy_intent: hasBuyIntent,
      has_question: hasQuestion
    }
  }
}];

// Parse AI response and apply decision rules
const aiResp = $input.item.json;
const ctx = $('Build: Context').item.json;

let ai;
try {
  let content = aiResp.choices[0].message.content;
  if (content.includes('```')) {
    content = content.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
  }
  ai = JSON.parse(content);
} catch (e) {
  // Fallback for unparseable AI response
  ai = {
    intent_type: 'question',
    confidence: 0.3,
    product_name: '',
    size: ctx.pre_parse.size || '',
    quantity: ctx.pre_parse.quantity || 0,
    color: '',
    customer_question: ctx.text,
    missing_fields: ['all'],
    suggested_reply: 'Спасибо за комментарий! Напишите нам в ЛС группы для подробной консультации.',
    should_create_order: false,
    should_write_demand: true
  };
}

// --- DECISION ENGINE ---
let finalIntent = ai.intent_type || 'question';
let finalConfidence = ai.confidence || 0.5;
let shouldCreateOrder = false;
let shouldWriteDemand = true;
let status = 'new_demand';

// Rule 1: buy_complete needs size and high confidence
if (finalIntent === 'buy_complete') {
  const hasSize = (ai.size || ctx.pre_parse.size || '') !== '';
  if (finalConfidence >= 0.8 && hasSize) {
    shouldCreateOrder = true;
    status = 'order_created';
    if (!ai.quantity || ai.quantity === 0) ai.quantity = 1; // safe default
  } else if (finalConfidence >= 0.6) {
    finalIntent = 'buy_incomplete';
    status = 'clarification_requested';
    if (!hasSize) ai.missing_fields = [...(ai.missing_fields || []), 'size'];
    ai.suggested_reply = ai.suggested_reply || 'Подскажите, какой размер вам нужен? Доступны: XS, S, M, L, XL, XXL.';
  } else {
    finalIntent = 'buy_incomplete';
    status = 'clarification_requested';
  }
}

// Rule 2: buy_incomplete
if (finalIntent === 'buy_incomplete') {
  status = 'clarification_requested';
  shouldCreateOrder = false;
  if (!ai.suggested_reply || ai.suggested_reply.length < 10) {
    const missing = (ai.missing_fields || []).join(', ') || 'детали заказа';
    ai.suggested_reply = `Здравствуйте! Уточните, пожалуйста: ${missing}. Напишите нам в ЛС для оформления.`;
  }
}

// Rule 3: question
if (finalIntent === 'question') {
  status = 'new_demand';
  shouldCreateOrder = false;
  if (!ai.suggested_reply || ai.suggested_reply.length < 10) {
    ai.suggested_reply = 'Здравствуйте! Спасибо за вопрос. Напишите нам в ЛС группы — подробно проконсультируем!';
  }
}

// Rule 4: clarification
if (finalIntent === 'clarification') {
  status = 'clarification_requested';
  shouldCreateOrder = false;
}

// Rule 5: ignore — only if high confidence
if (finalIntent === 'ignore') {
  if (finalConfidence < 0.7) {
    finalIntent = 'question';
    status = 'new_demand';
    ai.suggested_reply = 'Спасибо за комментарий! Если у вас есть вопросы — напишите нам в ЛС.';
  } else {
    status = 'ignored';
    shouldWriteDemand = true; // still log
  }
}

// Rule 6: Low confidence fallback
if (finalConfidence < 0.5 && finalIntent !== 'ignore') {
  shouldCreateOrder = false;
  if (!ai.suggested_reply || ai.suggested_reply.length < 10) {
    ai.suggested_reply = 'Спасибо за комментарий! Напишите нам в ЛС группы, ответим в ближайшее время.';
  }
}

const finalSize = ai.size || ctx.pre_parse.size || '';
const finalQty = ai.quantity || ctx.pre_parse.quantity || (shouldCreateOrder ? 1 : 0);

return [{
  json: {
    // Original context
    comment_id: ctx.comment_id,
    post_id: ctx.post_id,
    from_id: ctx.from_id,
    owner_id: ctx.owner_id,
    text: ctx.text,
    date: ctx.date,
    dedup_key: ctx.dedup_key,
    post_text: ctx.post_text,
    post_url: ctx.post_url,
    user_name: ctx.user_name,
    // AI classification
    intent_type: finalIntent,
    confidence: finalConfidence,
    product_name: ai.product_name || '',
    size: finalSize,
    quantity: finalQty,
    color: ai.color || '',
    customer_question: ai.customer_question || '',
    missing_fields: ai.missing_fields || [],
    suggested_reply: ai.suggested_reply || '',
    // Decision
    should_create_order: shouldCreateOrder,
    should_write_demand: shouldWriteDemand,
    status: status
  }
}];

